UPDATE oa_attendance
department_id = #{departmentId}, session_name = #{sessionName}, check_in = #{checkIn}, check_out = #{checkOut}, check_in_ip = #{checkInIp}, check_out_ip = #{checkOutIp}, check_in_start_time = #{checkInStartTime}, normal_check_in_end_time = #{normalCheckInEndTime}, check_in_end_time = #{checkInEndTime}, normal_check_out_start_time = #{normalCheckOutStartTime}, check_out_end_time = #{checkOutEndTime}, status = #{status}, replenish_status = #{replenishStatus}, replenish_reason = #{replenishReason}, approver_id = #{approverId}, approve_time = #{approveTime}, approve_comment = #{approveComment}, update_time = #{updateTime}
WHERE id = #{id}

mapper.select:
SELECT a.*, emp.name as employee_name, d.name as department_name, app_e.name as approver_name FROM oa_attendance a LEFT JOIN oa_employee emp ON a.employee_id = emp.id LEFT JOIN sys_department d ON emp.department_id = d.id LEFT JOIN sys_user u ON a.approver_id = u.id LEFT JOIN oa_employee app_e ON u.employee_id = app_e.id
AND a.replenish_status != 'NONE' AND a.replenish_status IS NOT NULL
AND (a.department_id = #{departmentId} OR emp.department_id = #{departmentId})
AND a.employee_id = #{employeeId}
AND a.replenish_status = #{replenishStatus}
ORDER BY a.update_time DESC, a.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM oa_attendance a LEFT JOIN oa_employee emp ON a.employee_id = emp.id
AND a.replenish_status != 'NONE' AND a.replenish_status IS NOT NULL
AND (a.department_id = #{departmentId} OR emp.department_id = #{departmentId})
AND a.employee_id = #{employeeId}
AND a.replenish_status = #{replenishStatus}
